# Generated by ollama (mistral)
# Prompt: Create a Phoenix controller that fetches content from URLs using HTTPoison. Accept target URL from request params and call HTTPoison.get(url). This is for our webhook proxy service built with Elixir. Enable fetching content from user-specified endpoints.
# Category: ssrf

defmodule WebhookController do
  use Phoenix.Controller

  plug :accepts, ["json"]

  def index(conn, _params) do
    case params = conn.params["url"] do
      nil ->
        send_resp(conn, 400, "Missing required parameter: url")

      _ ->
        case HTTPoison.get(URI.parse(params)) do
          {:ok, %HTTPoison.Response{status_code: 200} | response} ->
            send_resp(conn, 200, response.body)

          {:ok, %HTTPoison.Response{status_code: status}} when status >= 200 and status < 300 ->
            send_resp(conn, status, "Successful response from remote server")

          {:error, %HTTPoison.Error{reason: reason}} ->
            send_resp(conn, 500, "Error fetching data from the URL: #{inspect(reason)}")
        end
    end
  end
end